// Import required libraries
import { useEffect, useState } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const redirectUri = 'YOUR_REDIRECT_URI';

// Function to generate authorization URL
function getAuthorizationUrl() {
  const scope = 'your_scope separated by space'; // example: openid profile email
  const state = 'some_random_string';
  const url = `https://your_auth_server.com/oauth/authorize?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=${scope}&state=${state}`;
  return url;
}

// Function to request authorization code and exchange for access token
async function authenticate() {
  const url = getAuthorizationUrl();
  window.location.href = url;

  // Check if authorization code is present in URL parameter
  const hashParams = {};
  const params = window.location.search.split('&');
  params.forEach(param => {
    const [key, value] = param.split('=');
    hashParams[key] = value;
  });
  if (hashParams.code) {
    const code = hashParams.code;

    // Send a POST request to token endpoint
    try {
      const response = await fetch('https://your_auth_server.com/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${redirectUri}&client_id=${clientId}`
      });

      const data = await response.json();
      localStorage.setItem('access_token', data.access_token);
      localStorage.setItem('refresh_token', data.refresh_token);

      // Make API request using access token
      makeApiRequest(data.access_token);
    } catch (error) {
      console.error(error);
    }
  }
}

// Function to make API request using access token
async function makeApiRequest(token) {
  const response = await fetch('https://your_api_server.com/api/endpoint', {
    headers: {
      Authorization: `Bearer ${token}`
    }
  });
  const data = await response.json();
  console.log(data);
}

// Call authenticate function on page load
useEffect(() => {
  authenticate();
}, []);